            if 0 <= nx < w and 0 <= ny < h and (nx, ny) not in obstacles:
                return [ddx, ddy]
        return [0, 0]

    if resources:
        best = None
        best_score = None
        for tx, ty in resources:
            d1 = dist(sx, sy, tx, ty)
            d2 = dist(ox, oy, tx, ty)
            score = d1 - d2  # prefer resources where we're not behind
